// src/App.js
import React, { useEffect, useState } from "react";
import { Routes, Route, Navigate } from "react-router-dom";
import Login from "./pages/Login";
import Signup from "./pages/Signup";
import ForgotPassword from "./pages/ForgotPassword";
import DashboardLayout from "./Layout/DashboardLayout";
import DashboardHome from "./pages/DashboardHome";
import LiveTracking from "./pages/LiveTracking";
import RouteOptimization from "./pages/RouteOptimization";
import TrafficLayer from "./pages/TrafficLayer";
import Notifications from "./pages/Notifications";

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);

  // ✅ FIXED: Initialize authentication state
  useEffect(() => {
    const checkAuthStatus = async () => {
      const token = localStorage.getItem("token") || sessionStorage.getItem("token");

      if (token && token !== "null" && token !== "undefined") {
        console.log("🔍 Found token, validating:", token.substring(0, 20) + "...");

        // For demo token, immediately set as authenticated
        if (token === "FAKE_TOKEN_123") {
          console.log("✅ Demo token found, logging in");
          setIsAuthenticated(true);
          setLoading(false);
          return;
        }

        // For real JWT tokens, validate with backend
        try {
          console.log("🌐 Validating JWT token with backend...");
          const response = await fetch(`${process.env.REACT_APP_API_URL || 'http://localhost:8080/api'}/auth/validate`, {
            headers: {
              'Authorization': `Bearer ${token}`,
              'Content-Type': 'application/json'
            },
            timeout: 5000 // 5 second timeout
          });

          if (response.ok) {
            console.log("✅ Token validation successful");
            setIsAuthenticated(true);
          } else {
            console.log("❌ Token validation failed - status:", response.status);
            // Remove invalid token
            localStorage.removeItem("token");
            sessionStorage.removeItem("token");
            localStorage.removeItem("user");
            sessionStorage.removeItem("user");
            setIsAuthenticated(false);
          }
        } catch (error) {
          console.error("❌ Token validation error:", error.message);

          // ✅ FIX: On network/validation error, clear tokens and require login
          console.log("🧹 Clearing invalid tokens and requiring fresh login");
          localStorage.removeItem("token");
          sessionStorage.removeItem("token");
          localStorage.removeItem("user");
          sessionStorage.removeItem("user");
          setIsAuthenticated(false);
        }
      } else {
        console.log("ℹ️ No token found, showing login page");
        setIsAuthenticated(false);
      }

      setLoading(false);
    };

    checkAuthStatus();
  }, []);

  // ✅ Enhanced logout function
  const handleLogout = () => {
    console.log("🚪 Logging out user");
    localStorage.removeItem("token");
    sessionStorage.removeItem("token");
    localStorage.removeItem("user");
    sessionStorage.removeItem("user");

    // Clear any other app-specific data
    localStorage.removeItem("preferences");
    localStorage.removeItem("lastRoute");

    setIsAuthenticated(false);
  };

  // ✅ Protected Route Component
  const ProtectedRoute = ({ children }) => {
    if (loading) {
      return (
        <div className="flex items-center justify-center min-h-screen bg-gray-100">
          <div className="text-center">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500 mx-auto mb-4"></div>
            <p className="text-gray-600">Validating authentication...</p>
          </div>
        </div>
      );
    }

    if (!isAuthenticated) {
      console.log("🚫 Access denied - redirecting to login");
      return <Navigate to="/login" replace />;
    }

    return children;
  };

  // ✅ Auth Redirect Component
  const AuthRedirect = ({ children }) => {
    if (loading) {
      return (
        <div className="flex items-center justify-center min-h-screen bg-gray-100">
          <div className="text-center">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500 mx-auto mb-4"></div>
            <p className="text-gray-600">Checking authentication...</p>
          </div>
        </div>
      );
    }

    if (isAuthenticated) {
      console.log("✅ Already authenticated - redirecting to dashboard");
      return <Navigate to="/" replace />;
    }

    return children;
  };

  // ✅ Loading screen with better UX
  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-gray-100">
        <div className="text-center">
          <div className="flex items-center justify-center mb-4">
            <div className="flex space-x-2 mr-3">
              <span className="w-3 h-3 rounded-full bg-blue-500 animate-pulse"></span>
              <span className="w-3 h-3 rounded-full bg-red-500 animate-pulse delay-75"></span>
              <span className="w-3 h-3 rounded-full bg-yellow-400 animate-pulse delay-150"></span>
              <span className="w-3 h-3 rounded-full bg-green-500 animate-pulse delay-300"></span>
            </div>
            <h1 className="text-2xl font-bold text-gray-800">NeuroFleetX</h1>
          </div>
          <div className="animate-spin rounded-full h-16 w-16 border-b-2 border-blue-500 mx-auto mb-4"></div>
          <p className="text-gray-600">Initializing application...</p>
          <p className="text-sm text-gray-500 mt-2">Please wait while we set things up</p>
        </div>
      </div>
    );
  }

  return (
    <Routes>
      {/* ✅ Authentication Routes */}
      <Route
        path="/login"
        element={
          <AuthRedirect>
            <Login setIsAuthenticated={setIsAuthenticated} />
          </AuthRedirect>
        }
      />
      <Route
        path="/signup"
        element={
          <AuthRedirect>
            <Signup />
          </AuthRedirect>
        }
      />
      <Route
        path="/forgot-password"
        element={
          <AuthRedirect>
            <ForgotPassword />
          </AuthRedirect>
        }
      />

      {/* ✅ Protected Dashboard Routes */}
      <Route
        path="/"
        element={
          <ProtectedRoute>
            <DashboardLayout onLogout={handleLogout} />
          </ProtectedRoute>
        }
      >
        <Route index element={<DashboardHome />} />
        <Route path="live-tracking" element={<LiveTracking />} />
        <Route path="route-optimization" element={<RouteOptimization />} />
        <Route path="traffic-layer" element={<TrafficLayer />} />
        <Route path="notifications" element={<Notifications />} />
      </Route>

      {/* ✅ Fallback Route */}
      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  );
};

export default App;
